// Glossary data — parsed and cleaned from the AstuteApp user-flow glossaries.
// Each module keeps its own list; ALL_TERMS merges duplicates across modules.

export type Cat = "investor" | "firm" | "lender" | "admin";
export type GlossaryTerm = { term: string; def: string; cats: Cat[] };

export const CAT_META: Record<Cat, { label: string; color: string }> = {
  investor: { label: "Investor", color: "#38bdf8" },
  firm: { label: "Firm", color: "#a78bfa" },
  lender: { label: "Lender", color: "#34d399" },
  admin: { label: "Admin", color: "#fbbf24" },
};

type Pair = [string, string];
const build = (pairs: Pair[], cat: Cat): GlossaryTerm[] =>
  pairs.map(([term, def]) => ({ term, def, cats: [cat] }));

