export const INVESTOR_TERMS = build(INVESTOR, "investor");
export const FIRM_TERMS = build(FIRM, "firm");
export const LENDER_TERMS = build(LENDER, "lender");
export const ADMIN_TERMS = build(ADMIN, "admin");

/** Merge across modules: same term (case-insensitive) collapses into one entry
 *  that carries every category it appears in and keeps the fullest definition. */
function mergeAll(...groups: GlossaryTerm[][]): GlossaryTerm[] {
  const map = new Map<string, GlossaryTerm>();
  for (const group of groups) {
    for (const t of group) {
      const key = t.term.toLowerCase();
      const existing = map.get(key);
      if (existing) {
        for (const c of t.cats) if (!existing.cats.includes(c)) existing.cats.push(c);
        if (t.def.length > existing.def.length) existing.def = t.def;
      } else {
        map.set(key, { term: t.term, def: t.def, cats: [...t.cats] });
      }
    }
  }
  return [...map.values()].sort((a, b) => a.term.localeCompare(b.term, "en"));
}

export const ALL_TERMS = mergeAll(INVESTOR_TERMS, FIRM_TERMS, LENDER_TERMS, ADMIN_TERMS);
